func hydrateFacts(cmd *cobra.Command, flags *rootFlags, c *client.Client, s *store.Store, cert string) (json.RawMessage, error) {
	if cached, err := s.Get("coin", cert); err == nil {
		return cached, nil
	} else if err != sql.ErrNoRows {
		return nil, fmt.Errorf("cache probe %s: %w", cert, err)
	}
	path := replacePathParam("/coindetail/GetCoinFactsByCertNo/{certNo}", "certNo", cert)
	data, _, err := resolveRead(cmd.Context(), c, flags, "coin", false, path, nil, nil)
	if err != nil {
		return nil, classifyAPIError(err, flags)
	}
	if err := s.Upsert("coin", cert, data); err != nil {
		return nil, fmt.Errorf("upsert coin %s: %w", cert, err)
	}
	return data, nil
}

